// scrollCore.ts
export type ScrollDirection = "up" | "down";

export type ScrollState = {
    y: number;
    isScrolled: boolean;
    direction: ScrollDirection;
};

export function computeScrollState(
    prevY: number,
    currentY: number,
    threshold: number
) {
    return {
        y: currentY,
        isScrolled: currentY > threshold,
        direction: currentY > prevY ? "down" : "up",
    } as const;
}